mapper.select:
SELECT count(*) FROM hm_query.notification_flat

    AND customer_id = #{customerId}
    AND channel = #{channel}
    AND template_id = #{templateId}
    AND recipient_address LIKE CONCAT('%', #{recipientAddress}, '%')
    AND state_id = #{stateId}
    AND sent_at >= #{startDate}
    AND sent_at <= #{endDate}
    AND (subject LIKE CONCAT('%', #{q}, '%') OR recipient_address LIKE CONCAT('%', #{q}, '%') OR customer_name LIKE CONCAT('%', #{q}, '%'))

SELECT
    id,
    customer_id        as "customerId",
    customer_name      as "customerName",
    channel,
    template_id        as "templateId",
    subject,
    recipient_address  as "recipientAddress",
    sent_at            as "sentAt",
    delivered_at       as "deliveredAt",
    failure_reason     as "failureReason",
    retry_count        as "retryCount",
    state_id           as "stateId"
FROM hm_query.notification_flat

    AND customer_id = #{customerId}
    AND channel = #{channel}
    AND template_id = #{templateId}
    AND recipient_address LIKE CONCAT('%', #{recipientAddress}, '%')
    AND state_id = #{stateId}
    AND sent_at >= #{startDate}
    AND sent_at <= #{endDate}
    AND (subject LIKE CONCAT('%', #{q}, '%') OR recipient_address LIKE CONCAT('%', #{q}, '%') OR customer_name LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT state_id as "stateId", count(*) as "retryCount" FROM hm_query.notification_flat
AND state_id = #{stateId}
GROUP BY state_id

SELECT count(*)
FROM hm_query.notification_flat
WHERE state_id IN ('FAILED', 'BOUNCED')
AND customer_id = #{customerId}
AND channel = #{channel}

SELECT channel, state_id as "stateId", count(*) as "retryCount" FROM hm_query.notification_flat
AND channel = #{channel}
GROUP BY channel, state_id

SELECT count(*)
FROM hm_query.notification_flat
WHERE customer_id = #{customerId}
AND state_id = #{stateId}

SELECT count(*)
FROM hm_query.notification_flat
WHERE channel = #{channel}
AND state_id = #{stateId}

SELECT count(*)
FROM hm_query.notification_flat
WHERE template_id = #{templateId}
AND state_id = #{stateId}
